INSERT INTO questions (keyword, question, answer, category) VALUES
('java features', 'What are the main features of Java?', 'Java is platform-independent, object-oriented, robust, secure, multithreaded, and supports automatic memory management via garbage collection. It follows the write-once-run-anywhere principle through JVM bytecode compilation.', 'Java'),
('jdk jre jvm', 'What is the difference between JDK, JRE, and JVM?', 'JVM is the runtime engine that executes bytecode. JRE is the runtime environment that includes JVM and core libraries. JDK is the development kit that includes JRE plus development tools like compiler and debugger.', 'Java'),
('oop principles', 'What are the four pillars of OOP?', 'The four pillars are Encapsulation (bundling data and methods), Inheritance (acquiring parent properties), Polymorphism (same interface different implementations), and Abstraction (hiding complexity showing essentials).', 'Java'),
('encapsulation', 'What is encapsulation in Java?', 'Encapsulation is the bundling of data (variables) and methods that operate on that data into a single unit (class). It restricts direct access to fields using access modifiers and provides getter/setter methods for controlled access.', 'Java'),
('inheritance types', 'What are the types of inheritance in Java?', 'Java supports single, multilevel, and hierarchical inheritance through classes. Multiple inheritance is achieved through interfaces. Hybrid inheritance is not directly supported in Java.', 'Java'),
('polymorphism', 'What is polymorphism in Java?', 'Polymorphism allows objects to take multiple forms. Compile-time polymorphism is achieved through method overloading (same name, different parameters). Runtime polymorphism is achieved through method overriding in inheritance.', 'Java'),
('abstraction', 'What is abstraction in Java?', 'Abstraction is the concept of hiding implementation details and showing only functionality. It is achieved through abstract classes (partial abstraction) and interfaces (full abstraction). Abstract methods have no body and must be implemented by subclasses.', 'Java'),
('abstract class interface', 'What is the difference between abstract class and interface?', 'Abstract classes can have constructors, instance variables, and method implementations. Interfaces can only have constants and abstract methods (pre-Java 8). From Java 8+, interfaces support default and static methods. A class can implement multiple interfaces but extend only one abstract class.', 'Java'),
('string stringbuilder', 'What is the difference between String, StringBuilder, and StringBuffer?', 'String is immutable and creates new objects on modification. StringBuilder is mutable, not thread-safe, and faster. StringBuffer is mutable and thread-safe but slower due to synchronization. Use String for constants, StringBuilder for single-thread modifications.', 'Java'),
('final finally finalize', 'What is the difference between final, finally, and finalize?', 'final is a keyword to make variables constant, prevent method overriding, or prevent inheritance. finally is a block that always executes after try-catch. finalize is a method called by garbage collector before destroying an object.', 'Java'),
('exception handling', 'What is exception handling in Java?', 'Exception handling manages runtime errors using try-catch-finally blocks. Checked exceptions (IOException, SQLException) must be handled at compile time. Unchecked exceptions (NullPointerException, ArithmeticException) occur at runtime. The throws keyword declares exceptions, throw creates them.', 'Java'),
('checked unchecked exception', 'What is the difference between checked and unchecked exceptions?', 'Checked exceptions extend Exception and must be handled with try-catch or throws declaration at compile time. Unchecked exceptions extend RuntimeException and don't require explicit handling. Use checked for recoverable conditions, unchecked for programming errors.', 'Java'),
('collection framework', 'What is the Java Collections Framework?', 'The Java Collections Framework is a unified architecture for representing and manipulating collections. It includes interfaces (List, Set, Map, Queue), implementation classes (ArrayList, HashSet, HashMap), and algorithms (sorting, searching). It reduces programming effort and improves performance.', 'Java'),
('arraylist linkedlist', 'What is the difference between ArrayList and LinkedList?', 'ArrayList uses a dynamic array, provides O(1) random access, and is better for read-heavy operations. LinkedList uses doubly-linked list, provides O(1) insertion/deletion at ends, and is better for frequent modifications. ArrayList has less memory overhead per element.', 'Java'),
('hashmap', 'How does HashMap work in Java?', 'HashMap stores key-value pairs using hashing. It computes the bucket index from the key's hashCode(), handles collisions via chaining (linked list or tree for 8+ entries). Default capacity is 16, load factor 0.75. From Java 8, buckets with 8+ entries convert to TreeMap for O(log n) performance.', 'Java'),
('hashmap hashtable', 'What is the difference between HashMap and Hashtable?', 'HashMap is not thread-safe, allows one null key and multiple null values, and is faster. Hashtable is thread-safe (synchronized), doesn't allow null keys or values, and is slower. ConcurrentHashMap is the recommended thread-safe alternative to Hashtable.', 'Java'),
('multithreading', 'What is multithreading in Java?', 'Multithreading allows concurrent execution of multiple threads within a program. It can be achieved by extending Thread class or implementing Runnable interface. Java provides synchronization (synchronized keyword, locks) to prevent thread interference and memory consistency errors.', 'Java'),
('synchronization', 'What is synchronization in Java?', 'Synchronization controls access to shared resources by multiple threads. It can be applied to methods (synchronized keyword) or code blocks. Java provides intrinsic locks (monitor), ReentrantLock, ReadWriteLock, and atomic variables for thread safety. Over-synchronization can cause deadlocks.', 'Java'),
('thread lifecycle', 'What are the states in a thread lifecycle?', 'A thread can be in NEW (created), RUNNABLE (ready to run), RUNNING (executing), BLOCKED (waiting for lock), WAITING (waiting indefinitely), TIMED_WAITING (waiting with timeout), or TERMINATED (completed) state. State transitions are managed by the JVM and thread scheduler.', 'Java'),
('garbage collection', 'What is garbage collection in Java?', 'Garbage collection is automatic memory management that reclaims objects no longer referenced. JVM uses generational GC (Young, Old/Tenured, Metaspace). Common algorithms: Mark-Sweep, Copying, Mark-Compact. System.gc() suggests but doesn't force GC. Object.finalize() is called before collection.', 'Java'),
('serialization', 'What is serialization in Java?', 'Serialization converts an object into a byte stream for storage or transmission. Implement Serializable interface (marker interface). ObjectOutputStream writes, ObjectInputStream reads. transient keyword excludes fields. serialVersionUID ensures version compatibility. Used in RMI, JPA, and caching.', 'Java'),
('generics', 'What are generics in Java?', 'Generics enable type-safe code by parameterizing types. They provide compile-time type checking, eliminate casting, and enable generic algorithms. Bounded types (<T extends Class>), wildcards (? extends, ? super), and type erasure are key concepts. Introduced in Java 5.', 'Java'),
('lambda expressions', 'What are lambda expressions in Java?', 'Lambda expressions are anonymous functions introduced in Java 8. Syntax: (parameters) -> expression. They enable functional programming, work with functional interfaces (interfaces with one abstract method). Commonly used with Stream API, Optional, and event handlers. They reduce boilerplate code significantly.', 'Java'),
('stream api', 'What is the Stream API in Java?', 'Stream API (Java 8) provides a functional approach to processing collections. Operations are either intermediate (filter, map, sorted - lazy) or terminal (collect, forEach, reduce - eager). Streams support parallel processing, are non-interfering, and can be sequential or parallel.', 'Java'),
('optional class', 'What is the Optional class in Java?', 'Optional (Java 8) is a container that may or may not hold a value, designed to prevent NullPointerException. Methods: of(), ofNullable(), empty(), isPresent(), ifPresent(), orElse(), orElseGet(), orElseThrow(). It encourages explicit null handling and cleaner API design.', 'Java'),
('spring boot', 'What is Spring Boot?', 'Spring Boot simplifies Spring application development with auto-configuration, embedded servers, and production-ready features. It follows convention-over-configuration, provides starter dependencies, and eliminates boilerplate XML. Key features: @SpringBootApplication, application.properties, and Actuator.', 'Java'),
('dependency injection', 'What is dependency injection in Spring?', 'Dependency Injection (DI) is a design pattern where dependencies are provided externally rather than created internally. Spring supports constructor injection (recommended), setter injection, and field injection (@Autowired). DI promotes loose coupling, testability, and follows the IoC principle.', 'Java'),
('spring annotations', 'What are the common Spring annotations?', 'Core: @Component, @Service, @Repository, @Controller, @RestController. Web: @RequestMapping, @GetMapping, @PostMapping, @PathVariable, @RequestBody. DI: @Autowired, @Qualifier, @Value. Config: @Configuration, @Bean, @ComponentScan. Boot: @SpringBootApplication, @EnableAutoConfiguration.', 'Java'),
('jpa hibernate', 'What is JPA and Hibernate?', 'JPA (Java Persistence API) is a specification for ORM in Java. Hibernate is the most popular JPA implementation. It maps Java objects to database tables using annotations (@Entity, @Table, @Id). Provides HQL, criteria API, caching, and lazy loading. Reduces JDBC boilerplate code.', 'Java'),
('rest api', 'What is a REST API?', 'REST (Representational State Transfer) is an architectural style for web services. It uses HTTP methods: GET (read), POST (create), PUT (update all), PATCH (partial update), DELETE (remove). Principles: stateless, uniform interface, cacheable, layered system. Data format is typically JSON.', 'Java'),
('microservices', 'What are microservices?', 'Microservices is an architecture where an application is composed of small, independent services. Each service has its own database, can be deployed independently, and communicates via REST or messaging. Benefits: scalability, technology diversity, fault isolation. Challenges: distributed complexity, data consistency.', 'Java'),
('design patterns', 'What are the most common design patterns in Java?', 'Creational: Singleton, Factory, Builder, Prototype. Structural: Adapter, Decorator, Facade, Proxy. Behavioral: Observer, Strategy, Command, Iterator. Choose patterns based on the problem: Singleton for single instance, Factory for object creation, Observer for event handling, Strategy for algorithm selection.', 'Java'),
('singleton pattern', 'What is the Singleton design pattern?', 'Singleton ensures a class has only one instance and provides a global access point. Implement using private constructor, static instance, and getInstance() method. Thread-safe implementations: eager initialization, double-checked locking, or enum singleton (most robust). Beware of reflection and serialization breaking singleton.', 'Java'),
('jvm architecture', 'What is the architecture of JVM?', 'JVM has three subsystems: Class Loader (loading, linking, initialization), Runtime Data Area (method area, heap, stack, PC registers, native method stack), and Execution Engine (interpreter, JIT compiler, garbage collector). JIT compiler optimizes frequently executed bytecode into native machine code.', 'Java'),
('memory management', 'How does memory management work in Java?', 'JVM divides memory into Stack (method calls, local variables - per thread), Heap (objects - shared), Method Area (class metadata), and Native Method Stack. Heap is divided into Young Generation (Eden, S0, S1) and Old Generation. GC primarily works on Young Generation using minor collections.', 'Java'),
('java 8 features', 'What are the key features of Java 8?', 'Java 8 introduced Lambda Expressions, Stream API, Optional, Functional Interfaces, Default methods in interfaces, Date/Time API (java.time), Method References, CompletableFuture, and Nashorn JavaScript engine. These features enable functional programming and significantly reduce boilerplate code.', 'Java'),
('java 11 features', 'What are the key features of Java 11?', 'Java 11 (LTS) introduced HTTP Client (standardized), String new methods (isBlank, lines, strip, repeat), Files new methods (readString, writeString), Optional.isEmpty(), Local-Variable Syntax for Lambda parameters, Flight Recorder, and removed Java EE modules. It's the most widely used LTS version.', 'Java'),
('java 17 features', 'What are the key features of Java 17?', 'Java 17 (LTS) introduced Sealed Classes, Pattern Matching for switch (preview), Record classes (standardized), Text Blocks, Switch Expressions, instanceof pattern matching, and removed deprecated features like Applet API. It provides stronger encapsulation and better null handling.', 'Java'),
('concurrent hashmap', 'What is ConcurrentHashMap in Java?', 'ConcurrentHashMap provides thread-safe operations without locking the entire map. It divides the map into segments (Java 7) or uses CAS and synchronized on bucket heads (Java 8+). Read operations are lock-free, write operations lock only the affected bucket. Preferred over Hashtable and synchronized HashMap.', 'Java'),
('volatile keyword', 'What is the volatile keyword in Java?', 'volatile ensures variable visibility across threads - reads always return the latest write by any thread. It prevents thread caching of variables and establishes happens-before relationship. However, it doesn't ensure atomicity for compound operations. Use AtomicXxx classes for atomic read-modify-write operations.', 'Java'),
('functional interface', 'What is a functional interface in Java?', 'A functional interface has exactly one abstract method and can be annotated with @FunctionalInterface. Examples: Predicate<T>, Function<T,R>, Consumer<T>, Supplier<T>, Comparator<T>. They enable lambda expressions and method references. Default and static methods don't count toward the single abstract method limit.', 'Java');
INSERT INTO questions (keyword, question, answer, category) VALUES
('dbms definition', 'What is DBMS?', 'DBMS (Database Management System) is software for creating, managing, and manipulating databases. It provides data independence, security, integrity, concurrency control, and recovery. Types include Relational (MySQL, PostgreSQL), NoSQL (MongoDB, Cassandra), and Object-oriented DBMS.', 'DBMS'),
('sql nosql', 'What is the difference between SQL and NoSQL?', 'SQL databases are relational, use structured schemas, support ACID, and scale vertically. NoSQL databases are non-relational, flexible schema, support BASE, and scale horizontally. Choose SQL for complex queries and consistency, NoSQL for flexibility and horizontal scaling.', 'DBMS'),
('acid properties', 'What are ACID properties?', 'ACID ensures reliable transactions: Atomicity (all-or-nothing execution), Consistency (database moves from one valid state to another), Isolation (concurrent transactions don't interfere), Durability (committed data persists even on failure). Essential for financial and mission-critical systems.', 'DBMS'),
('normalization', 'What is normalization in databases?', 'Normalization organizes data to reduce redundancy and dependency. 1NF: atomic values, no repeating groups. 2NF: no partial dependencies. 3NF: no transitive dependencies. BCNF: every determinant is a candidate key. Most applications normalize to 3NF for optimal balance.', 'DBMS'),
('1nf 2nf 3nf', 'What are the first three normal forms?', '1NF: Each column contains atomic (indivisible) values, each row is unique. 2NF: Meets 1NF and all non-key attributes are fully dependent on the entire primary key (no partial dependencies). 3NF: Meets 2NF and no non-key attribute depends on another non-key attribute (no transitive dependencies).', 'DBMS'),
('denormalization', 'What is denormalization?', 'Denormalization is the process of adding redundancy to a normalized database to improve read performance. It reduces the number of joins needed for queries but increases storage and complicates updates. Use when read performance is critical and write operations are infrequent.', 'DBMS'),
('primary key', 'What is a primary key?', 'A primary key uniquely identifies each record in a table. It must be unique, not null, and rarely changed. A composite primary key uses multiple columns. Surrogate keys (auto-increment) are preferred over natural keys for performance and stability. Each table can have only one primary key.', 'DBMS'),
('foreign key', 'What is a foreign key?', 'A foreign key is a column that references the primary key of another table, establishing a relationship. It enforces referential integrity - prevents orphan records and ensures valid cross-table references. Actions on delete/update: CASCADE, SET NULL, RESTRICT, NO ACTION.', 'DBMS'),
('indexing', 'What is indexing in databases?', 'An index is a data structure that speeds up data retrieval at the cost of write performance and storage. B-tree indexes are most common, supporting range queries. Hash indexes excel at equality checks. Composite indexes follow the leftmost prefix rule. Over-indexing slows down INSERT/UPDATE operations.', 'DBMS'),
('clustered nonclustered index', 'What is the difference between clustered and non-clustered index?', 'Clustered index sorts and stores data rows physically in order (one per table, usually primary key). Non-clustered index creates a separate structure with pointers to data rows (multiple per table). Clustered is faster for range queries, non-clustered for specific lookups. A table scan occurs without proper indexes.', 'DBMS'),
('join types', 'What are the types of SQL joins?', 'INNER JOIN: matching rows from both tables. LEFT JOIN: all left rows + matched right rows (NULL if no match). RIGHT JOIN: all right rows + matched left rows. FULL OUTER JOIN: all rows from both tables. CROSS JOIN: Cartesian product. SELF JOIN: table joined with itself.', 'DBMS'),
('group by having', 'What is the difference between GROUP BY and HAVING?', 'GROUP BY groups rows sharing common values for aggregation functions (COUNT, SUM, AVG, MAX, MIN). HAVING filters groups after aggregation (like WHERE but for groups). WHERE filters individual rows before grouping. Order: WHERE → GROUP BY → HAVING → SELECT → ORDER BY.', 'DBMS'),
('where having', 'What is the difference between WHERE and HAVING?', 'WHERE filters individual rows before grouping and cannot use aggregate functions. HAVING filters groups after GROUP BY and can use aggregate functions. WHERE is applied first, then GROUP BY, then HAVING. Use WHERE for row conditions, HAVING for group conditions.', 'DBMS'),
('transaction', 'What is a database transaction?', 'A transaction is a logical unit of work consisting of one or more operations. It follows ACID properties. Commands: BEGIN TRANSACTION, COMMIT (save changes), ROLLBACK (undo changes), SAVEPOINT (partial rollback). Transactions ensure data consistency even during system failures.', 'DBMS'),
('deadlock', 'What is a deadlock in databases?', 'A deadlock occurs when two or more transactions wait indefinitely for each other's locks. Detection: wait-for graph, timeout. Prevention: lock ordering, lock timeouts. Resolution: victim selection and rollback. MySQL InnoDB detects deadlocks automatically and rolls back the smaller transaction.', 'DBMS'),
('concurrency control', 'What is concurrency control?', 'Concurrency control manages simultaneous access to the database. Techniques: Lock-based (shared/exclusive locks, two-phase locking), Timestamp-based, Optimistic (validation at commit), and Multi-version (MVCC). MVCC allows readers to not block writers and vice versa, used by PostgreSQL and MySQL InnoDB.', 'DBMS'),
('isolation levels', 'What are the SQL isolation levels?', 'From lowest to highest: READ UNCOMMITTED (dirty reads possible), READ COMMITTED (no dirty reads), REPEATABLE READ (no dirty/non-repeatable reads - MySQL default), SERIALIZABLE (no dirty/non-repeatable/phantom reads). Higher isolation = more consistency but less concurrency.', 'DBMS'),
('phantom read', 'What is a phantom read?', 'A phantom read occurs when a transaction re-executes a range query and finds new rows that weren't there before, due to another transaction inserting them. Prevented by SERIALIZABLE isolation level or key-range locks. Non-repeatable reads differ - they involve modified rows, not new ones.', 'DBMS'),
('stored procedure', 'What is a stored procedure?', 'A stored procedure is precompiled SQL code stored in the database. Benefits: performance (precompiled), security (encapsulate logic), reusability, reduced network traffic. Created with CREATE PROCEDURE, called with EXEC/EXECUTE. Supports parameters (IN, OUT, INOUT), variables, and control flow.', 'DBMS'),
('trigger', 'What is a database trigger?', 'A trigger is automatic code executed in response to DML events (INSERT, UPDATE, DELETE) on a table. Types: BEFORE/AFTER, ROW/STATEMENT. Uses: audit logging, data validation, derived column maintenance. Disadvantages: hidden logic, debugging difficulty, performance impact. Use sparingly.', 'DBMS'),
('view', 'What is a database view?', 'A view is a virtual table based on a query result. Benefits: security (column/row masking), simplicity (hide complexity), consistency (centralized query logic). Types: simple (single table, updatable) and complex (joins, aggregates, read-only). Materialized views store actual data for performance.', 'DBMS'),
('cursor', 'What is a cursor in SQL?', 'A cursor allows row-by-row processing of query results. Types: Implicit (auto-created by DBMS) and Explicit (developer-defined). Lifecycle: DECLARE → OPEN → FETCH → CLOSE. Used when set-based operations aren't sufficient. Avoid cursors when possible - set-based operations are typically faster.', 'DBMS'),
('erd', 'What is an Entity-Relationship Diagram?', 'An ERD visually represents database structure using entities (tables), relationships (associations), and attributes (columns). Notations: Chen, Crow's Foot, UML. Cardinality: 1:1, 1:N, M:N. ERD is the blueprint for database design before creating actual tables and relationships.', 'DBMS'),
('cardinality', 'What is cardinality in databases?', 'Cardinality defines the number of relationships between entities. One-to-One: each entity instance relates to exactly one of the other. One-to-Many: one instance relates to multiple others. Many-to-Many: multiple instances relate to multiple others (requires junction table).', 'DBMS'),
('database schema', 'What is a database schema?', 'A schema is the structural blueprint of a database - defines tables, columns, data types, constraints, relationships, and indexes. Logical schema: table definitions and relationships. Physical schema: how data is stored on disk. Schemas provide namespace isolation and security boundaries.', 'DBMS'),
('partitioning', 'What is database partitioning?', 'Partitioning divides large tables into smaller, manageable pieces. Horizontal: splits rows (range, list, hash, composite). Vertical: splits columns. Benefits: improved query performance, easier maintenance, parallel processing. Use when tables exceed millions of rows. Each partition can be managed independently.', 'DBMS'),
('sharding', 'What is database sharding?', 'Sharding distributes data across multiple database instances (horizontal scaling). Each shard holds a subset of data. Strategies: hash-based, range-based, directory-based. Benefits: scalability, performance. Challenges: cross-shard queries, distributed transactions, rebalancing. Used by large-scale applications like social media platforms.', 'DBMS'),
('replication', 'What is database replication?', 'Replication copies data across multiple servers for availability and performance. Types: Master-Slave (one write, multiple reads), Master-Master (multiple write nodes), Synchronous (immediate consistency), Asynchronous (eventual consistency). MySQL uses binlog replication, PostgreSQL uses WAL streaming.', 'DBMS'),
('backup recovery', 'What are database backup and recovery strategies?', 'Backup types: Full (complete database), Incremental (changes since last backup), Differential (changes since last full backup), Log backup (transaction logs). Recovery models: Simple (no point-in-time), Full (point-in-time recovery), Bulk-logged. Strategy: full weekly + differential daily + log every 15 minutes.', 'DBMS'),
('query optimization', 'What is query optimization?', 'Query optimization finds the most efficient execution plan. The optimizer considers: index usage, join order, access methods, and cost estimation. Techniques: use indexes, avoid SELECT *, use EXPLAIN/EXPLAIN ANALYZE, limit results, avoid functions on indexed columns, use appropriate joins.', 'DBMS'),
('explain plan', 'What is EXPLAIN in SQL?', 'EXPLAIN shows the query execution plan without running it. It reveals: table access methods (full scan vs index), join strategies, estimated rows, and cost. EXPLAIN ANALYZE actually runs the query with timing. Use it to identify: missing indexes, sequential scans, expensive joins, and sort operations.', 'DBMS'),
('cap theorem', 'What is the CAP theorem?', 'CAP theorem states distributed systems can guarantee at most two of: Consistency (all nodes see same data), Availability (every request gets a response), Partition tolerance (system works despite network partitions). Since partitions are inevitable, the real choice is CP or AP. BASE is the alternative to ACID for AP systems.', 'DBMS'),
('mongodb', 'What is MongoDB?', 'MongoDB is a document-oriented NoSQL database storing data as BSON (binary JSON) documents. Features: flexible schema, horizontal scaling via sharding, rich queries, aggregation pipeline, ACID transactions (4.0+). Use cases: content management, real-time analytics, IoT data, and rapid prototyping.', 'DBMS'),
('redis database', 'What is Redis?', 'Redis is an in-memory key-value store used as database, cache, and message broker. Data structures: strings, lists, sets, sorted sets, hashes, streams. Features: pub/sub, Lua scripting, transactions, persistence (RDB/AOF). Sub-millisecond latency. Use cases: caching, session store, leaderboards, rate limiting.', 'DBMS'),
('mysql engine', 'What is the difference between MyISAM and InnoDB?', 'InnoDB supports transactions, row-level locking, foreign keys, and crash recovery (ACID compliant). MyISAM supports table-level locking, full-text search, and is faster for read-heavy workloads. InnoDB is the default since MySQL 5.5 and recommended for most use cases. Use MyISAM only for read-only or log tables.', 'DBMS'),
('connection pooling', 'What is connection pooling?', 'Connection pooling maintains a cache of database connections for reuse. Creating connections is expensive, so pooling reduces overhead. Configurations: min/max connections, idle timeout, max lifetime. Implementations: HikariCP (fastest), c3p0, DBCP. Critical for high-throughput applications to prevent connection exhaustion.', 'DBMS');
INSERT INTO questions (keyword, question, answer, category) VALUES
('tell me about yourself', 'Tell me about yourself.', 'Structure your answer: Present (current role/situation), Past (relevant experience and key achievements), Future (why you are here and what excites you). Keep it under 2 minutes, focus on professional highlights, and connect your background to the role. Avoid personal details not relevant to the position.', 'HR'),
('strengths', 'What are your strengths?', 'Choose 2-3 strengths directly relevant to the role. Use the STAR method to provide evidence. Example: "My analytical skills helped me reduce processing time by 40% at my last role by identifying bottlenecks." Be specific, avoid generic answers like "hard worker," and always back claims with results.', 'HR'),
('weaknesses', 'What are your weaknesses?', 'Choose a genuine area for improvement and explain your strategy to address it. Example: "I sometimes take on too many tasks, so I now use priority matrices to focus on what matters most." Show self-awareness and growth mindset. Never say "perfectionist" or claim you have no weaknesses.', 'HR'),
('why should we hire you', 'Why should we hire you?', 'Connect your unique combination of skills, experience, and enthusiasm to the company's specific needs. Reference the job description, mention relevant achievements with metrics, and demonstrate you've researched the company. Show both competence and cultural fit. Be confident but not arrogant.', 'HR'),
('where do you see yourself', 'Where do you see yourself in 5 years?', 'Show ambition aligned with the company's growth path. Focus on skill development, increasing responsibility, and contributing to the organization. Example: "I see myself leading larger projects and mentoring junior team members, while deepening my expertise in cloud architecture." Avoid mentioning unrelated career changes.', 'HR'),
('why do you want to work here', 'Why do you want to work here?', 'Demonstrate genuine research about the company: mention their products, culture, recent news, or mission. Connect your career goals to what the company offers. Example: "Your commitment to AI innovation aligns with my passion for building intelligent systems, and I'm excited about the opportunity to contribute to Project X."', 'HR'),
('why leaving current job', 'Why are you leaving your current job?', 'Stay positive - never badmouth your current employer. Focus on seeking growth, new challenges, or better alignment with your career goals. Example: "I've learned a lot at my current role, but I'm looking for opportunities to work on larger-scale systems and expand into cloud architecture." Frame it as moving toward, not running from.', 'HR'),
('salary expectations', 'What are your salary expectations?', 'Research market rates beforehand. Provide a range rather than a fixed number. Example: "Based on my research and experience, I'm targeting the range of $X-$Y, but I'm flexible and would consider the total compensation package." Let them make the first offer if possible. Consider benefits, equity, and growth potential.', 'HR'),
('conflict resolution', 'How do you handle conflict at work?', 'Describe your approach: listen first, understand perspectives, find common ground, and focus on solutions not blame. Use STAR: "When a teammate and I disagreed on architecture, I scheduled a meeting to understand their concerns, we compared trade-offs, and chose the approach that best served the project timeline."', 'HR'),
('leadership style', 'What is your leadership style?', 'Be authentic and describe your actual approach: servant leadership, transformational, democratic, etc. Give examples of how you've motivated teams, delegated effectively, and developed talent. "I believe in empowering team members by giving them ownership while providing support and removing blockers."', 'HR'),
('failure example', 'Tell me about a time you failed.', 'Choose a real failure that you learned from. Structure: situation, what went wrong, what you learned, how you applied the lesson. Example: "I underestimated a project timeline, causing a delayed delivery. I learned to build buffer time and communicate risks early. Since then, I've delivered all projects on schedule using better estimation techniques."', 'HR'),
('teamwork example', 'Give an example of teamwork.', 'Use STAR method: describe the team goal, your specific role, how you collaborated, and the result. Highlight communication, compromise, and shared success. "When our team had to deliver a feature in 2 weeks, I organized daily standups, paired with a senior dev on complex logic, and we delivered a day early."', 'HR'),
('stress management', 'How do you handle stress?', 'Show healthy coping mechanisms: prioritization, time management, exercise, and asking for help when needed. Example: "When stressed, I prioritize tasks using the Eisenhower matrix, break large tasks into smaller steps, and communicate with stakeholders about realistic timelines. I also maintain a regular exercise routine."', 'HR'),
('motivation', 'What motivates you?', 'Be genuine - mention intrinsic motivators like problem-solving, learning, impact, and recognition. Connect to the role: "I'm motivated by solving complex technical challenges and seeing my solutions improve users' lives. That's why I'm drawn to this role - the scale of impact your platform has is exciting."', 'HR'),
('biggest achievement', 'What is your biggest professional achievement?', 'Choose an achievement relevant to the role with measurable impact. Use STAR: "I led the migration of a legacy system to microservices, reducing deployment time from 2 days to 15 minutes and improving uptime from 99.5% to 99.99%. It required cross-team collaboration and careful planning over 6 months."', 'HR'),
('challenge example', 'Describe a challenging situation you faced.', 'Use STAR method. Focus on a professional challenge where you took initiative. "Our production system crashed during peak hours. I quickly identified the memory leak, implemented a hotfix, and then created a monitoring system to catch similar issues early. No production incidents since then."', 'HR'),
('adaptability', 'How do you adapt to change?', 'Show flexibility and positive attitude toward change. Give an example: "When our team switched from Waterfall to Agile, I embraced it by studying Scrum practices, suggesting sprint retrospectives, and helping teammates adjust. Within two sprints, our delivery velocity improved by 30%."', 'HR'),
('time management', 'How do you prioritize your work?', 'Describe your system: Eisenhower matrix, MoSCoW method, or custom approach. "I categorize tasks by urgency and impact. Critical and important tasks get done first. I use time-blocking for deep work and batch similar tasks. I review priorities daily and adjust based on changing business needs."', 'HR'),
('feedback', 'How do you handle feedback?', 'Show openness and growth mindset. "I appreciate constructive feedback as it helps me improve. When I received feedback about my code documentation, I immediately started adding detailed comments and created a documentation template. My next code review received positive comments on clarity."', 'HR'),
('delegation', 'How do you delegate tasks?', 'Show you trust your team and provide clear direction. "I delegate based on team members' strengths and development goals. I provide clear expectations, necessary resources, and check-in points without micromanaging. For example, I delegated the API design to a junior developer who wanted to learn, while providing guidance."', 'HR'),
('work life balance', 'How do you maintain work-life balance?', 'Show you're productive but sustainable. "I set clear boundaries by prioritizing tasks during work hours and avoiding non-urgent after-hours work. I use time-blocking for focused work and regular breaks to maintain energy. A balanced life makes me more productive and creative at work."', 'HR'),
('company culture', 'What type of work environment do you prefer?', 'Be honest but align with the company's culture. Research their values beforehand. "I thrive in collaborative environments where team members support each other and share knowledge. I also appreciate having focused time for deep work. From what I've read about your culture, it seems like a great fit."', 'HR'),
('questions for us', 'Do you have any questions for us?', 'Always have thoughtful questions prepared. Good options: "What does success look like in this role in the first 6 months?" "What are the biggest challenges the team is facing?" "How does the team approach professional development?" "What's the team's approach to work-life balance?" Avoid questions about salary/vacation in early rounds.', 'HR'),
('remote work', 'How do you work effectively remotely?', 'Show discipline and communication skills. "I maintain a dedicated workspace, stick to a routine, and over-communicate through daily standups and status updates. I use tools like Slack and video calls to stay connected. I also make time for virtual team bonding to maintain relationships."', 'HR'),
('career change', 'Why are you changing careers?', 'Frame it as a positive evolution. "My previous experience gave me transferable skills - analytical thinking, project management, and communication. I've been building technical skills through courses and personal projects, and I'm excited to apply my unique perspective to software engineering."', 'HR'),
('overqualified', 'Aren\'t you overqualified for this position?', 'Show enthusiasm for the specific role, not just any job. "I'm drawn to this role specifically because of the team and projects. I believe my experience allows me to contribute immediately while continuing to grow. I value the opportunity to make an impact in a role where I can also learn new things."', 'HR'),
('ethical dilemma', 'Describe an ethical dilemma you faced.', 'Choose a real situation showing integrity. "I discovered a vendor was overcharging our company. Despite pressure to ignore it, I documented the issue, presented it to management with evidence, and we renegotiated the contract, saving $50K annually. Doing the right thing isn't always easy but it's always right."', 'HR'),
('innovation example', 'Give an example of when you were innovative.', 'Show creative problem-solving. "Our deployment process took 4 hours manually. I automated it using CI/CD pipelines, reducing it to 20 minutes. I also created a rollback mechanism for safety. This innovation saved the team 15+ hours per week and reduced deployment errors by 90%."', 'HR'),
('learning new technology', 'How do you learn a new technology?', 'Show a structured approach. "I start with official documentation and tutorials, then build a small project to apply concepts. I read source code of popular libraries, follow industry experts, and participate in communities. For example, I learned React by building a task manager app, then contributing to an open-source project."', 'HR'),
('why gap in employment', 'Can you explain the gap in your employment?', 'Be honest and positive. "I took time to care for a family member / complete certifications / travel and gain new perspectives. During that time, I kept my skills current by working on personal projects and taking online courses. I'm now fully ready and excited to return to full-time work."', 'HR');
